const http = require('http');
const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

// ── HTTP helpers (n8n sandbox: no axios, no fetch) ──────────────
const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):(\/\/)([^:/]+)(?::(\d+))?(\/?[^?]*)(\?.*)?$/);
  if (!m) return reject(new Error('Invalid URL: ' + urlStr));
  const hostname = m[3];
  const port = m[4] ? parseInt(m[4]) : 80;
  const reqPath = (m[5] || '/') + (m[6] || '');
  const options = { hostname, port, path: reqPath, method, headers: {} };
  if (body) {
    options.headers['Content-Type'] = 'application/json';
    options.headers['Content-Length'] = Buffer.byteLength(body);
  }
  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
    });
  });
  req.on('error', reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, bodyObj) => httpRequest('POST', url, JSON.stringify(bodyObj));
const httpGet  = (url)          => httpRequest('GET',  url, null);
const sleep = ms => new Promise(r => setTimeout(r, ms));

// ── Parameters ──────────────────────────────────────────────────
const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const orientationFilter = (params.OrientationFilter || '').trim().toLowerCase();
const comfyAPI = 'http://127.0.0.1:8188';
const COMFY_OUTPUT = 'D:/ComfyUI_windows_portable/ComfyUI/output';
const FFMPEG = 'D:/ComfyUI_windows_portable/ffmpeg-8.0.1-full_build/bin/ffmpeg.exe';

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const musicDir = ((deck.Assets && deck.Assets.MusicDirectory)
  ? deck.Assets.MusicDirectory
  : path.join(deckDir, 'Music')).replace(/\//g, path.sep);

fs.mkdirSync(musicDir, { recursive: true });

// ── Deck-level music defaults ───────────────────────────────────
const deckMusic = (deck.Prompts && deck.Prompts.Music) || {};
const models = deck.Models || {};

const DECK_BASE_STYLE   = deckMusic.BaseStyle || '';
const DECK_NEGATIVE      = deckMusic.Negative || '';
const DECK_DURATION      = deckMusic.Duration || 15;
const DECK_BPM           = deckMusic.BPM || 80;
const DECK_KEY_SCALE     = deckMusic.KeyScale || 'D minor';
const DECK_STEPS         = deckMusic.InferenceSteps || 100;
const DECK_CFG           = deckMusic.CFG || 7.0;
const DECK_SEED          = deckMusic.Seed !== undefined ? deckMusic.Seed : -1;
const MUSIC_CHECKPOINT   = models.MusicCheckpoint || 'stable-audio-open-1.0.safetensors';
const MUSIC_TEXT_ENCODER  = models.MusicTextEncoder || 't5-base.safetensors';

// ── Post-processing filter chain ────────────────────────────────
// FFT denoise → bass boost (+6dB at 150Hz) → mid-bass EQ (+3dB at
// 250Hz) → EBU R128 loudness normalization
const PP_FILTER = 'afftdn=nf=-25,bass=g=6:f=150:w=0.5,equalizer=f=250:t=h:w=200:g=3,loudnorm=I=-14:TP=-1:LRA=11';
const CROSSFADE_DURATION = 2; // seconds for seamless loop crossfade

// ── Build ComfyUI API prompt (Stable Audio Open 1.0) ────────────
//
// Node graph:
//   1: CheckpointLoaderSimple → MODEL(0), _CLIP(1)_, VAE(2)
//   2: CLIPLoader (stable_audio, t5-base) → CLIP(0)
//   3: CLIPTextEncode (positive) → CONDITIONING(0)
//   4: CLIPTextEncode (negative) → CONDITIONING(0)
//   5: ConditioningStableAudio → positive(0), negative(1)
//   6: EmptyLatentAudio → LATENT(0)
//   7: KSampler → LATENT(0)
//   8: VAEDecodeAudio → AUDIO(0)
//   9: SaveAudioMP3 → UI output
//
function buildMusicPrompt(positiveText, negativeText, duration, seed, filenamePrefix) {
  const actualSeed = (seed === -1)
    ? Math.floor(Math.random() * 2147483647)
    : seed;

  return {
    "1": {
      "class_type": "CheckpointLoaderSimple",
      "inputs": {
        "ckpt_name": MUSIC_CHECKPOINT
      }
    },
    "2": {
      "class_type": "CLIPLoader",
      "inputs": {
        "clip_name": MUSIC_TEXT_ENCODER,
        "type": "stable_audio"
      }
    },
    "3": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": positiveText,
        "clip": ["2", 0]
      }
    },
    "4": {
      "class_type": "CLIPTextEncode",
      "inputs": {
        "text": negativeText,
        "clip": ["2", 0]
      }
    },
    "5": {
      "class_type": "ConditioningStableAudio",
      "inputs": {
        "positive": ["3", 0],
        "negative": ["4", 0],
        "seconds_start": 0.0,
        "seconds_total": duration
      }
    },
    "6": {
      "class_type": "EmptyLatentAudio",
      "inputs": {
        "seconds": duration,
        "batch_size": 1
      }
    },
    "7": {
      "class_type": "KSampler",
      "inputs": {
        "model": ["1", 0],
        "positive": ["5", 0],
        "negative": ["5", 1],
        "latent_image": ["6", 0],
        "seed": actualSeed,
        "steps": DECK_STEPS,
        "cfg": DECK_CFG,
        "sampler_name": "dpmpp_3m_sde",
        "scheduler": "sgm_uniform",
        "denoise": 1.0
      }
    },
    "8": {
      "class_type": "VAEDecodeAudio",
      "inputs": {
        "samples": ["7", 0],
        "vae": ["1", 2]
      }
    },
    "9": {
      "class_type": "SaveAudioMP3",
      "inputs": {
        "audio": ["8", 0],
        "filename_prefix": filenamePrefix,
        "quality": "320k"
      }
    }
  };
}

// ── Extract output audio file from ComfyUI history ──────────────
function extractAudioFile(historyEntry) {
  const outputs = historyEntry.outputs || {};
  const saveOut = outputs['9'];
  if (!saveOut) return null;
  for (const key of ['audio', 'gifs', 'images', 'results']) {
    if (saveOut[key] && saveOut[key].length > 0) {
      return saveOut[key][0];
    }
  }
  return null;
}

// ── ffmpeg post-processing ──────────────────────────────────────
function postProcessAudio(inputPath, outputPath) {
  try {
    execFileSync(FFMPEG, [
      '-y', '-i', inputPath,
      '-af', PP_FILTER,
      outputPath
    ], { encoding: 'utf8', stdio: 'pipe' });
    return true;
  } catch (e) {
    console.warn('[Post-process] ffmpeg failed: ' + (e.stderr || e.message));
    fs.copyFileSync(inputPath, outputPath);
    return false;
  }
}

// ── Seamless loop crossfade ─────────────────────────────────────
// Creates a seamless loop by crossfading the tail into the head:
//   [main] = CROSSFADE_DURATION to (duration - CROSSFADE_DURATION)
//   [loop] = acrossfade of tail and head
// Result: plays main, then crossfade seamlessly back to head.
// When looped, the end of [loop] is identical to where [main]
// starts, creating a gapless transition.
function makeSeamlessLoop(inputPath) {
  const tmpPath = inputPath.replace(/\.mp3$/, '_preloop.mp3');
  try {
    fs.renameSync(inputPath, tmpPath);
  } catch(e) {
    console.warn('[Loop] Cannot rename for crossfade: ' + e.message);
    return false;
  }
  const xd = CROSSFADE_DURATION;
  const dur = DECK_DURATION;
  const mainEnd = dur - xd;  // e.g., 13 for 15s with 2s xfade
  const filter = [
    '[0]asplit=3[main_src][tail_src][head_src]',
    '[main_src]atrim=start=' + xd + ':end=' + mainEnd + ',asetpts=N/SR/TB[main]',
    '[tail_src]atrim=start=' + mainEnd + ',asetpts=N/SR/TB[tail]',
    '[head_src]atrim=end=' + xd + ',asetpts=N/SR/TB[head]',
    '[tail][head]acrossfade=d=' + xd + ':c1=tri:c2=tri[xfade]',
    '[main][xfade]concat=n=2:v=0:a=1'
  ].join('; ');
  try {
    execFileSync(FFMPEG, [
      '-y', '-i', tmpPath,
      '-filter_complex', filter,
      inputPath
    ], { encoding: 'utf8', stdio: 'pipe' });
    fs.unlinkSync(tmpPath);
    return true;
  } catch(e) {
    console.warn('[Loop] Crossfade failed: ' + (e.stderr || e.message).substring(0, 300));
    // Restore original
    try { fs.renameSync(tmpPath, inputPath); } catch(e2) {}
    return false;
  }
}

// ── Card processing ─────────────────────────────────────────────
const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Generate Music] No Cards found in Deck.json.');
}

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error(
    '[Generate Music] No cards matched filter: ' +
    JSON.stringify(testCardFilter) +
    '. Check TestCardFilter matches a Card name in Deck.json.'
  );
}

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(
    deckDir, cardRef.File.replace(/\//g, path.sep)
  );

  let cardRaw;
  try {
    cardRaw = JSON.parse(
      fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, '')
    );
  } catch (e) {
    console.warn('[Generate Music] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const records = card.records || [];
  let cardModified = false;

  for (const record of records) {
    const orientation = record.Orientation;
    if (!orientation) continue;

    // Apply orientation filter if set
    if (orientationFilter && orientation.toLowerCase() !== orientationFilter) continue;

    const cardMusic = (record.Prompts && record.Prompts.Music) || {};
    const tags = cardMusic.Tags;
    if (!tags) {
      console.warn('[Generate Music] No Tags for ' + cardName + ' ' + orientation + ', skipping.');
      results.skipped++;
      results.cards.push({
        card: cardName, orientation, status: 'skipped',
        reason: 'No Prompts.Music.Tags'
      });
      continue;
    }

    // Build target filename
    const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
    const targetFilename = 'MUSIC_' + slug + '_' + orientation + '.mp3';
    const targetPath = path.join(musicDir, targetFilename);

    // Skip if file already exists (insertable/overridable assets)
    if (fs.existsSync(targetPath)) {
      results.skipped++;
      results.cards.push({
        card: cardName, orientation, status: 'skipped',
        reason: 'Already exists'
      });
      continue;
    }

    // Build positive prompt: combine deck base style + card tags +
    // BPM/key metadata for Stable Audio text conditioning
    const bpm = cardMusic.BPM || DECK_BPM;
    const keyScale = cardMusic.KeyScale || DECK_KEY_SCALE;
    const fullPositive = [
      DECK_BASE_STYLE,
      tags,
      bpm + ' BPM',
      keyScale
    ].filter(Boolean).join(', ');
    const filenamePrefix = 'MUSIC_' + slug + '_' + orientation;

    // Build and submit ComfyUI prompt
    const prompt = buildMusicPrompt(
      fullPositive, DECK_NEGATIVE,
      DECK_DURATION, DECK_SEED, filenamePrefix
    );

    try {
      const submitResult = await httpPost(
        comfyAPI + '/prompt', { prompt }
      );
      if (submitResult.error) {
        throw new Error('ComfyUI reject: ' + JSON.stringify(submitResult.error));
      }
      if (!submitResult.prompt_id) {
        throw new Error('No prompt_id in response: ' + JSON.stringify(submitResult));
      }
      const promptId = submitResult.prompt_id;

      // Poll until done (up to 10 min per clip)
      let outputFile = null;
      for (let attempt = 0; attempt < 120 && !outputFile; attempt++) {
        await sleep(5000);
        const history = await httpGet(comfyAPI + '/history/' + promptId);
        const entry = history[promptId];
        if (!entry) continue;

        // Check for execution error
        if (entry.status && entry.status.status_str === 'error') {
          const msgs = entry.status.messages || [];
          throw new Error('ComfyUI execution error: ' + JSON.stringify(msgs));
        }

        outputFile = extractAudioFile(entry);
      }

      if (!outputFile) {
        throw new Error('Timeout waiting for ComfyUI output (10 min)');
      }

      // Post-process: denoise + bass boost + loudness normalization
      const comfyFilePath = path.join(
        COMFY_OUTPUT.replace(/\//g, path.sep),
        outputFile.subfolder || '',
        outputFile.filename
      );

      if (!fs.existsSync(comfyFilePath)) {
        throw new Error('Output file not found: ' + comfyFilePath);
      }

      const ppOk = postProcessAudio(comfyFilePath, targetPath);

      // Apply seamless loop crossfade
      const loopOk = makeSeamlessLoop(targetPath);

      // Update card JSON
      if (!record.Assets) record.Assets = {};
      record.Assets.Music = targetFilename;
      cardModified = true;

      results.processed++;
      results.cards.push({
        card: cardName,
        orientation,
        status: 'generated',
        postProcessed: ppOk,
        looped: loopOk,
        file: targetFilename,
        prompt: fullPositive.length > 120 ? fullPositive.substring(0, 120) + '...' : fullPositive
      });

    } catch (e) {
      console.warn(
        '[Generate Music] Failed: ' + cardName + ' ' + orientation +
        ': ' + e.message
      );
      results.failed++;
      results.cards.push({
        card: cardName, orientation, status: 'failed',
        reason: e.message
      });
    }
  }

  // Save updated card JSON if any records were modified
  if (cardModified) {
    try {
      fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');
    } catch (e) {
      console.warn('[Generate Music] Cannot save card JSON: ' + cardName + ': ' + e.message);
    }
  }
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error(
    '[Generate Music] No records processed. ' +
    'Check TestCardFilter and that card records have Prompts.Music.Tags.'
  );
}

return [{ json: results }];
